package org.apache.commons.csv;
import java.io.BufferedReader;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class ExtendedBufferedReaderTest {

    private ExtendedBufferedReader readerSpy;

    @BeforeEach
    void setUp() {
        Reader mockReader = mock(Reader.class);
        readerSpy = Mockito.spy(new ExtendedBufferedReader(mockReader));
    }

    @Test
    void testRead_lengthZero_returnsZero() throws IOException {
        char[] buf = new char[10];
        int result = readerSpy.read(buf, 0, 0);
        assertEquals(0, result);
        verify(readerSpy, never()).read(any(char[].class), anyInt(), anyInt());
    }

    @Test
    void testRead_lenPositive_noNewlineOrCarriageReturn() throws IOException {
        char[] buf = new char[10];
        // Spy super.read to return 3 and fill buf with chars without \n or \r
        doAnswer(invocation -> {
            char[] b = invocation.getArgument(0);
            int off = invocation.getArgument(1);
            int len = invocation.getArgument(2);
            b[off] = 'a';
            b[off + 1] = 'b';
            b[off + 2] = 'c';
            return 3;
        }).when(readerSpy).read(any(char[].class), anyInt(), anyInt());

        int result = readerSpy.read(buf, 1, 3);
        assertEquals(3, result);
        // lineCounter and lastChar should be updated accordingly
        // lastChar should be 'c' (buf[1+3-1])
        assertEquals((int) 'c', getPrivateField(readerSpy, "lastChar"));
        // lineCounter should remain 0
        assertEquals((int) 0, getPrivateField(readerSpy, "lineCounter"));
    }

    @Test
    void testRead_lenPositive_withNewlinesAndCarriageReturns() throws IOException {
        char[] buf = new char[10];
        // Prepare buf content: offset=1, length=5
        // chars: 'a', '\n', '\n', '\r', '\n'
        doAnswer(invocation -> {
            char[] b = invocation.getArgument(0);
            int off = invocation.getArgument(1);
            b[off] = 'a';
            b[off + 1] = '\n';
            b[off + 2] = '\n';
            b[off + 3] = '\r';
            b[off + 4] = '\n';
            return 5;
        }).when(readerSpy).read(any(char[].class), anyInt(), anyInt());

        // Set lastChar to something other than '\r' for testing
        setPrivateField(readerSpy, "lastChar", (int) 'x');
        int result = readerSpy.read(buf, 1, 5);
        assertEquals(5, result);

        // lineCounter increments:
        // i=1: 'a' no increment
        // i=2: '\n' preceded by 'a' != '\r' increment lineCounter (1)
        // i=3: '\n' preceded by '\n' != '\r' increment lineCounter (2)
        // i=4: '\r' increment lineCounter (3)
        // i=5: '\n' preceded by '\r' no increment
        assertEquals((int) 3, getPrivateField(readerSpy, "lineCounter"));
        // lastChar should be buf[offset + len -1] = buf[1+5-1] = buf[5] = '\n'
        assertEquals((int) '\n', getPrivateField(readerSpy, "lastChar"));
    }

    @Test
    void testRead_lenPositive_withNewlinePrecededByCarriageReturn() throws IOException {
        char[] buf = new char[10];
        // buf offset=0, length=3: '\r', '\n', 'a'
        doAnswer(invocation -> {
            char[] b = invocation.getArgument(0);
            int off = invocation.getArgument(1);
            b[off] = '\r';
            b[off + 1] = '\n';
            b[off + 2] = 'a';
            return 3;
        }).when(readerSpy).read(any(char[].class), anyInt(), anyInt());

        setPrivateField(readerSpy, "lastChar", (int) 'x');
        int result = readerSpy.read(buf, 0, 3);
        assertEquals(3, result);

        // lineCounter increments:
        // i=0: '\r' increment (1)
        // i=1: '\n' preceded by '\r' no increment
        // i=2: 'a' no increment
        assertEquals((int) 1, getPrivateField(readerSpy, "lineCounter"));
        assertEquals((int) 'a', getPrivateField(readerSpy, "lastChar"));
    }

    @Test
    void testRead_lenNegativeOne_setsEndOfStream() throws IOException {
        char[] buf = new char[10];
        // Spy super.read to return -1
        doReturn(-1).when(readerSpy).read(any(char[].class), anyInt(), anyInt());

        setPrivateField(readerSpy, "lastChar", (int) 'x');
        int result = readerSpy.read(buf, 0, 5);
        assertEquals(-1, result);
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, getPrivateField(readerSpy, "lastChar"));
    }

    // Helper method to get private fields via reflection
    @SuppressWarnings("unchecked")
    private <T> T getPrivateField(Object instance, String fieldName) {
        try {
            java.lang.reflect.Field field = ExtendedBufferedReader.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            Object val = field.get(instance);
            if (val instanceof Character) {
                return (T) (Integer) ((Character) val).charValue();
            }
            return (T) val;
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    // Helper method to set private fields via reflection
    private void setPrivateField(Object instance, String fieldName, Object value) {
        try {
            java.lang.reflect.Field field = ExtendedBufferedReader.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            if (field.getType() == int.class && value instanceof Character) {
                field.set(instance, (int) ((Character) value).charValue());
            } else if (field.getType() == int.class && value instanceof Integer) {
                field.set(instance, value);
            } else {
                field.set(instance, value);
            }
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
